import { useStore } from '@veltdev/crdt-react';

const { value: items, update: updateItems, store, isLoading, error } = useStore<Item[]>({
  storeId: 'my-array-store',
  type: 'array',
  initialValue: [{ id: '1', name: 'First item' }],
});

// Always guard with Array.isArray before spread/map
const itemList = Array.isArray(items) ? items : [];

// Add item
const addItem = (name: string) => {
  const current = store.getValue() || [];
  if (Array.isArray(current)) {
    updateItems([...current, { id: generateId(), name }]);
  }
};

import { useStore } from '@veltdev/crdt-react';

type DataMap = Record<string, any>;

const { value: entries, update: updateEntries, store } = useStore<DataMap>({
  storeId: 'my-map-store',
  type: 'map',
  initialValue: { key1: 'value1' },
});

// Guard: value is object (not array)
const entriesMap = (entries && typeof entries === 'object' && !Array.isArray(entries)) ? entries : {};

// Update a single key
const setKey = (key: string, val: any) => {
  const current = store.getValue() || {};
  updateEntries({ ...current, [key]: val });
};

import { useStore } from '@veltdev/crdt-react';

const { value: text, update: updateText, store } = useStore<string>({
  storeId: 'my-text-store',
  type: 'text',
  initialValue: '',
});

return (
  <textarea
    value={text ?? ''}
    onChange={(e) => updateText(e.target.value)}
  />
);

import { useStore } from '@veltdev/crdt-react';
import * as Y from 'yjs';
import { useEffect, useRef } from 'react';

// xml type requires: npm i yjs
function Component() {
  const xmlRef = useRef<Y.XmlFragment | null>(null);

  const { store, isLoading, error } = useStore<string>({
    storeId: 'my-xml-store',
    type: 'xml',
    // Do NOT call update() on xml stores — use store.getXml() instead
  });

  useEffect(() => {
    if (!store) return;
    const xml = store.getXml() as unknown as Y.XmlFragment | null;
    if (!xml) return;
    xmlRef.current = xml;

    // Populate with initial content if the document is empty
    if (xml.length === 0) {
      const doc = store.getDoc();
      doc.transact(() => {
        populateInitialContent(xml);
      });
    }
  }, [store]);
}
